import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

describe("@dependency", () => {
  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_dependency
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_01
    it("Dependencies.<Name> with Standard type and Active status", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @dependency(#{
          title: "My Lib",
          type: DependencyType.Standard,
          status: DependencyStatus.Active,
          sources: #[#{ url: "https://docs.example.com", description: "API docs" }]
        })
        namespace Dependencies.MyLib;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_04
    it("Dependencies.<Name> with Service type and Deprecated status", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @dependency(#{
          title: "Old API",
          type: DependencyType.Service,
          status: DependencyStatus.Deprecated,
          sources: #[]
        })
        namespace Dependencies.OldApi;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_05
    it("Dependencies.<Name> with Library type and Planned status", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @dependency(#{
          title: "Future Lib",
          type: DependencyType.Library,
          status: DependencyStatus.Planned,
          sources: #[]
        })
        namespace Dependencies.FutureLib;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_07
    it("with why, how, gotchas documentation fields", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @dependency(#{
          title: "Auth Service",
          type: DependencyType.Standard,
          status: DependencyStatus.Active,
          sources: #[],
          why: #["We need this for authentication"],
          how: #["Call POST /token with credentials"],
          gotchas: #["Token expires after 1 hour"]
        })
        namespace Dependencies.AuthService;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_02
    it("with @assumption attached", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @dependency(#{
          title: "External API",
          type: DependencyType.Service,
          status: DependencyStatus.Active,
          sources: #[]
        })
        @assumption(#{ id: "A01", assumption: "API is available", source: "https://example.com" })
        namespace Dependencies.ExternalApi;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_06
    it("Dependencies.<Name> with Evaluation status", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @dependency(#{
          title: "New Lib",
          type: DependencyType.Standard,
          status: DependencyStatus.Evaluation,
          sources: #[]
        })
        namespace Dependencies.NewLib;
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_03
    it("namespace not starting with Dependencies.", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @dependency(#{
          title: "My Lib",
          type: DependencyType.Standard,
          status: DependencyStatus.Active,
          sources: #[]
        })
        namespace MyLib;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Dependencies\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_08
    it("bare top-level namespace", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @dependency(#{
          title: "GitHub",
          type: DependencyType.Standard,
          status: DependencyStatus.Active,
          sources: #[]
        })
        namespace Github;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_09
    it("too many segments (Dependencies.Foo.Bar)", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @dependency(#{
          title: "Foo",
          type: DependencyType.Standard,
          status: DependencyStatus.Active,
          sources: #[]
        })
        namespace Dependencies.Foo.Bar;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_10
    it("unresolved inline ref in why", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @dependency(#{
          title: "My Lib",
          type: DependencyType.Standard,
          status: DependencyStatus.Active,
          sources: #[],
          why: #["We need {@GhostType} for this"]
        })
        namespace Dependencies.MyLib;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/unresolved-inline-ref",
        message: /GhostType/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T008.T008_11
    it("unresolved inline ref in gotchas", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @dependency(#{
          title: "My Lib",
          type: DependencyType.Standard,
          status: DependencyStatus.Active,
          sources: #[],
          gotchas: #["Watch out for {@GhostModel} responses"]
        })
        namespace Dependencies.MyLib;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/unresolved-inline-ref",
        message: /GhostModel/,
      });
    });
  });
});
